// Shape the API response into 6 named template variables that
// match the WhatsApp template 'daily_prep_summary'. Order MUST stay
// in sync with template body: {{1}} date, {{2}} lunch count, {{3}}
// lunch list, {{4}} dinner count, {{5}} dinner list, {{6}} notes.
//
// WhatsApp template parameters reject empty strings and trim trailing
// newlines, so we coerce numbers to strings and fall back to '无'.

const data = $input.first().json;

const safe = (s) => {
  if (s === undefined || s === null) return '无';
  const str = String(s).trim();
  return str.length > 0 ? str : '无';
};

return [{
  json: {
    var1: safe(data.date),
    var2: safe(data.lunch?.count ?? 0),
    var3: safe(data.lunch?.summaryText),
    var4: safe(data.dinner?.count ?? 0),
    var5: safe(data.dinner?.summaryText),
    var6: safe(data.notesText),
    // also pass through raw for debugging
    _raw: data,
  }
}];

// Surface failures clearly. Replace this with a Slack/Email node
// hooked to your own number if you want push notifications on failure.
const err = $input.first().json;
console.error('[daily-prep] WhatsApp send failed', JSON.stringify(err));
return [{ json: { error: err } }];
